<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aeroloongclaw:aeroloongclaw</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> groups/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> data/</span></span>
